class Solution:
    def repeatedStringMatch(self, a: str, b: str) -> int:
        n = len(a)
        m = len(b)
        if n > m:
            return -1
        if n == m:
            return 1 if a == b else -1
        j = 0
        count = 1
        while j < m:
            if a[j % n] == b[j]:
                j += 1
            count += 1
        if j == m:
            return count
        count += 1
        j = 0
        while j < m:
            if a[j % n] == b[j]:
                j += 1
            if j == m:
                return count
        return -1
```
